(function () {
  function addStyle() { if (document.getElementById('lrs-style')) return; var s = document.createElement('style'); s.id = 'lrs-style'; s.textContent = '.lrs-wrap{border:1px solid #e5e7eb;border-radius:12px;padding:16px;background:#fff;margin:14px 0}.lrs-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(120px,1fr));gap:12px;align-items:end}.lrs-grid label{display:flex;flex-direction:column;gap:5px}.lrs-grid input{padding:8px;border:1px solid #cbd5e1;border-radius:8px}.lrs-out{margin-top:12px;padding:12px;border-radius:8px;background:#f8f9fa;line-height:1.7}.lrs-note{padding:10px;border-left:4px solid #007bff;background:#e8f4fd;border-radius:8px}.lrs-table{width:100%;border-collapse:collapse;margin-top:10px}.lrs-table th,.lrs-table td{border:1px solid #e5e7eb;padding:7px;text-align:center}'; document.head.appendChild(s); }
  function fmt(x) { return Math.abs(x) < 1e-9 ? '0' : (Math.round(x * 1000) / 1000).toString(); }
  function mount(host) { if (!host || host.dataset.lrsMounted) return; host.dataset.lrsMounted = '1'; addStyle(); host.innerHTML = '<div class="lrs-wrap"><h4>📈 Giải truy hồi tuyến tính bậc 2</h4><div class="lrs-grid"><label>c1 <input data-c1 type="number" step="any" value="5"></label><label>c2 <input data-c2 type="number" step="any" value="-6"></label><label>a0 <input data-a0 type="number" step="any" value="2"></label><label>a1 <input data-a1 type="number" step="any" value="5"></label><button type="button" data-run>Giải</button></div><div class="lrs-out"></div></div>'; var out = host.querySelector('.lrs-out'); function val(k) { return parseFloat(host.querySelector(k).value) || 0; } function run() { var c1 = val('[data-c1]'), c2 = val('[data-c2]'), a0 = val('[data-a0]'), a1 = val('[data-a1]'), d = c1 * c1 + 4 * c2, rows = [], text; for (var n = 0, seq = [a0, a1]; n < 10; n++) { if (n > 1) seq[n] = c1 * seq[n - 1] + c2 * seq[n - 2]; rows.push('<tr><td>' + n + '</td><td>' + fmt(seq[n]) + '</td></tr>'); } if (d < 0) { var re = c1 / 2, im = Math.sqrt(-d) / 2; text = '<div class="lrs-note">Phương trình đặc trưng: r² - (' + fmt(c1) + ')·r - (' + fmt(c2) + ') = 0</div><p>Nghiệm phức: r1 = ' + fmt(re) + ' + ' + fmt(im) + 'i, r2 = ' + fmt(re) + ' - ' + fmt(im) + 'i.</p><p>Công thức thực dùng dạng lượng giác; bảng dưới vẫn tính đúng từ truy hồi.</p>'; } else { var r1 = (c1 + Math.sqrt(d)) / 2, r2 = (c1 - Math.sqrt(d)) / 2, beta, alpha; if (Math.abs(r1 - r2) < 1e-9) { alpha = a0; beta = r1 ? a1 / r1 - a0 : 0; text = '<div class="lrs-note">Phương trình đặc trưng: r² - (' + fmt(c1) + ')·r - (' + fmt(c2) + ') = 0</div><p>Nghiệm kép r = ' + fmt(r1) + '. Dạng đúng: a_n = (α + βn)·r^n.</p><p>α = ' + fmt(alpha) + ', β = ' + fmt(beta) + '.</p>'; } else { beta = (a1 - a0 * r1) / (r2 - r1); alpha = a0 - beta; text = '<div class="lrs-note">Phương trình đặc trưng: r² - (' + fmt(c1) + ')·r - (' + fmt(c2) + ') = 0</div><p>r1 = ' + fmt(r1) + ', r2 = ' + fmt(r2) + '</p><p>a_n = α·r1^n + β·r2^n, với α = ' + fmt(alpha) + ', β = ' + fmt(beta) + '.</p>'; } } out.innerHTML = text + '<table class="lrs-table"><tr><th>n</th><th>a_n</th></tr>' + rows.join('') + '</table>'; } host.querySelector('[data-run]').addEventListener('click', run); run(); }
  document.addEventListener('DOMContentLoaded', function () { document.querySelectorAll('[data-demo="linear-recurrence-solver"]').forEach(mount); });
}());
